//相比于exec多接收了环境变量数组这一参数，但还没有进行任何处理，故和exec相同
/*
  执行一个指定的程序；

  输入：
  + path: 待执行程序路径名称，
  + argv: 程序的参数，
  + envp: 环境变量的数组指针

  返回值：成功不返回，失败返回-1；
*/

uint64
sys_execve(void)
{
  char path[MAXPATH], *argv[MAXARG], *envp[MAXENV];
  int i;
  uint64 uargv, uarg, uenvp;


  if (argstr(0, path, MAXPATH) < 0 || argaddr(1, &uargv) < 0 || argaddr(2, &uenvp) < 0)
  {
    return -1;
  }

  printf("[sys_execve] path: %s\n", path);

  memset(argv, 0, sizeof(argv));
  for (i = 0;; i++)
  {
    if (i >= NELEM(argv))
    {
      goto bad;
    }
    if (fetchaddr(uargv + sizeof(uint64) * i, (uint64 *)&uarg) < 0)
    {
      goto bad;
    }
    if (uarg == 0)
    {
      argv[i] = 0;
      break;
    }
    argv[i] = kalloc();
    if (argv[i] == 0)
      goto bad;
    if (fetchstr(uarg, argv[i], PGSIZE) < 0)
      goto bad;
  }

  memset(envp, 0, sizeof(envp));
  int ret = execve(path, argv, envp);

  for (i = 0; i < NELEM(argv) && argv[i] != 0; i++)
    kfree(argv[i]);
  for (i = 0; i < NELEM(envp) && envp[i] != 0; i++)
    kfree(envp[i]);

  return ret;

bad:
  for (i = 0; i < NELEM(argv) && argv[i] != 0; i++)
    kfree(argv[i]);
  for (i = 0; i < NELEM(envp) && envp[i] != 0; i++)
    kfree(envp[i]);
  return -1;
}

