sys_rt_sigaction(void)
{
  int signum;
  uint64 actaddr, oactaddr;

  if (argint(0, &signum) < 0 || argaddr(1, &actaddr) < 0 || argaddr(2, &oactaddr) < 0)
    return -1;

  struct sigaction act = {0};
  struct sigaction oldact = {0};

  if (actaddr)
  {
    if (copyin2((char *)&act, actaddr, sizeof(act)) < 0)
      return -1;
  }

  if (sigaction(signum, actaddr ? &act : NULL, oactaddr ? &oldact : NULL) < 0)
  {
    return -1;
  }


  if (oactaddr)
  {
    if (copyout2(oactaddr, (char *)&oldact, sizeof(oldact)) < 0)
      return -1;
  }

  return 0;
}

uint64
sys_rt_sigprocmask(void)
{
  int how;
  uint64 setaddr, oldsetaddr;
  __sigset_t set, oldset;

  if (argint(0, &how) < 0 || argaddr(1, &setaddr) < 0 || argaddr(2, &oldsetaddr) < 0)
    return -1;

  if (setaddr)
  {
    if (copyin2((char *)&set, setaddr, sizeof(set)) < 0)
      return -1;
  }


  if (sigprocmask(how, &set, oldsetaddr ? &oldset : NULL))
  {
    return -1;
  }

  if (oldsetaddr)
  {
    if (copyout2(oldsetaddr, (char *)&oldset, sizeof(oldset)) < 0)
      return -1;
  }

  return 0;
}

