uint64
sys_dup3(void)
{
  // printf("dup3\n");
  struct file *f;
  int new;
  int fd;
  if(argfd(0, 0, &f) < 0 || argint(1, &new) < 0 || (fd = fdalloc2(f, new)) < 0)
    return -1;

  filedup(f);
  return fd;
}

