int sigaction(int signum, struct sigaction *act, struct sigaction *oldact)
{
    // printf("sigaction start\n");

    struct proc *current = myproc();

    if (signum < 1 || signum > NSIG)
        return -1;

    if(oldact)
        *oldact = current->sigaction[signum];

    if(act)
        current->sigaction[signum] = *act;

    // printf("sigaction ok\n");

    return 0;
}

int sigprocmask(int how, __sigset_t *set, __sigset_t *oldset)
{
    // printf("sigprocmask start\n");

    struct proc *current = myproc();

    // set->__val[0] &= ~((1 << SIGTERM) | (1 << SIGKILL));
    for (int i = 0; i < SIGSET_LEN; i++){
        if(oldset){
            oldset->__val[i] = current->sig_set.__val[i];
        }

        switch (how)
        {
        case SIG_BLOCK:
            current->sig_set.__val[i] |= set->__val[i];
            break;
        case SIG_UNBLOCK:
            current->sig_set.__val[i] &= ~(set->__val[i]);
            break;
        case SIG_SETMASK:
            current->sig_set.__val[i] = set->__val[i];
            break;
        default:
            panic("invalid how\n");
        }
    }
    current->sig_set.__val[0] &= 1UL << SIGTERM | 1UL << SIGKILL | 1UL << SIGSTOP;

    // printf("sigprocmask ok\n");

    return 0;
}

extern char sig_trampoline[];
extern char sig_handler[];
extern char default_sigaction[];

void sighandle(void)
{
    printf("[sighandle] enter sighandler\n");
    struct proc *p = myproc();

    int signum = 0;
    if (p->killed){
        signum = p->killed;
        const int len = sizeof(unsigned long) * 8;
        int i = (unsigned long)(p->killed) / len;
        int bit = (unsigned long)(p->killed) % len;
        p->sig_pending.__val[i] &= ~(1ul << bit++);
        p->killed = 0;

        for (; i < SIGSET_LEN; i++){
            while (bit < len){
                if (p->sig_pending.__val[i] & (1ul << bit)){
                    p->killed = i * len + bit;
                    goto start_handle;
                }
                bit++;
            }
        }
    }
    else
        return;

    struct sig_frame *frame;
    struct trapframe *tf;

    struct sigaction* sigact;

start_handle:

    sigact = &p->sigaction[signum];

    if (signum == SIGCHLD && (sigact == NULL || sigact->__sigaction_handler.sa_handler == NULL))
        return;

    frame = kmalloc(sizeof(struct sig_frame));

    tf = kmalloc(sizeof(struct trapframe));

    // copy mask
    for (int i = 0; i < SIGSET_LEN; i++){
        frame->mask.__val[i] = p->sig_set.__val[i];
        if (sigact == NULL)
            p->sig_set.__val[i] = 0;
        else
            p->sig_set.__val[i] &= sigact->sa_mask.__val[i];
    }

    // store proc's trapframe
    frame->tf = p->trapframe;
    tf->epc = (uint64)(SIG_TRAMPOLINE + ((uint64)sig_handler - (uint64)sig_trampoline));
    tf->sp = p->trapframe->sp;
    tf->a0 = signum;
    if (sigact && sigact->__sigaction_handler.sa_handler)
        tf->a1 = (uint64)(sigact->__sigaction_handler.sa_handler);
    else{
        // use the default handler
        printf("[sighandle] using default handler\n");
        tf->a1 = (uint64)(SIG_TRAMPOLINE + ((uint64)default_sigaction - (uint64)sig_trampoline));
    }

    p->trapframe = tf;
    // insert sig_frame into proc's sig_frame list
    frame->next = p->sig_frame;
    p->sig_frame = frame;
}

void sigreturn(void)
{
    printf("[sigreturn] enter sigreturn\n");
    struct proc *p = myproc();

    if (p->sig_frame == NULL){ // it's not in a sighandler!
        exit(-1);
    }

    struct sig_frame *frame = p->sig_frame;

    for (int i = 0; i < SIGSET_LEN; i++){
        p->sig_set.__val[i] = frame->mask.__val[i];
    }

    kmfree(p->trapframe);
    p->trapframe = frame->tf;

    // remove this frame from list
    p->sig_frame = frame->next;
    kmfree(frame);
}

