uint64 mmap(uint64 start, uint64 len, int prot, int flags, int fd, long int offset)
{
    // printf("[mmap] doing mmap\n");
    struct proc *p = myproc();

    int perm = PTE_V;

    if (prot & PROT_READ)
        perm |= PTE_R;
    if (prot & PROT_WRITE)
        perm |= PTE_W;
    if (prot & PROT_EXEC)
        perm |= PTE_X;

    // map with file
    if (fd >= 0)
    {
        if (flags & MAP_FIXED)
        { // fixed mapping
            /*
              TODO: you have to munmap exist mapping before fixed mapping
              no need to implement in pre
            */
            panic("[mmap] fixed mapping\n");
            return -1;
        }
        else
        {
            int index;

            index = new_seg(MMAP, start, len, flags);
            if (index != -1)
            {
#ifdef DEBUG
                // printf("new segment created.\n");
#endif
                p->segments[index].f_off = offset;
                p->segments[index].mmap = fd;

                struct ext4_file *file = &p->ofile[fd]->file;
                if (len + offset > file->fsize)
                    return -1;

                uint64 va = p->segments[index].addr;
                uint64 offset = offset;
                char *mem;

                int a;
                for (a = va; a < va + len; a += PGSIZE)
                {
                    uint64 size = a + PGSIZE < len ? PGSIZE : va + len - a;

                    mem = kalloc();
                    if (mem == NULL)
                    {
                        uvmdealloc(p->pagetable, p->kpagetable, a, p->sz);
                        return -1;
                    }
                    memset(mem, 0, PGSIZE);

                    if (mappages(p->pagetable, a, PGSIZE, (uint64)mem, perm | PTE_U) != 0)
                    {
                        kfree(mem);
                        uvmdealloc(p->pagetable, p->kpagetable, a, p->sz);
                        return -1;
                    }
                    if (mappages(p->kpagetable, a, PGSIZE, (uint64)mem, perm) != 0)
                    {
                        int npages = (a - p->sz) / PGSIZE;
                        vmunmap(p->pagetable, p->sz, npages + 1, 1); // plus the page allocated above.
                        vmunmap(p->kpagetable, p->sz, npages, 0);
                        return -1;
                    }
                    p->sz += PGSIZE;

                    uint64 pa = (uint64)walkaddr(p->pagetable, a);
                    fread(file, pa, offset, size, NULL);

                    if (size != PGSIZE)
                        memset((void *)(pa + size), 0, PGSIZE - size);

                    offset += size;
                }

                // printf("return with %p\n", p->segments[index].addr);
                filedup(p->ofile[p->segments[index].mmap]);
                return p->segments[index].addr;
            }
            else
                return -1;
        }
    }
    else
    {
        /*
          anonymous mapping
        */
        // printf("anonymous mapping\n");

        // return uvmalloc(myproc()->pagetable, myproc()->kpagetable, myproc()->sz,  myproc()->sz + PGSIZE);
        return myproc()->sz;
    }
}

// Physical memory allocator, for user processes,
// kernel stacks, page-table pages,
// and pipe buffers. Allocates whole 4096-byte pages.


#include "include/types.h"
#include "include/param.h"
#include "include/memlayout.h"
#include "include/riscv.h"
#include "include/spinlock.h"
#include "include/kalloc.h"
#include "include/string.h"
#include "include/printf.h"

void freerange(void *pa_start, void *pa_end);

extern char kernel_end[]; // first address after kernel.

struct run {
  struct run *next;
};

struct {
  struct spinlock lock;
  struct run *freelist;
  uint64 npage;
} kmem;

void
kinit()
{
  initlock(&kmem.lock, "kmem");
  kmem.freelist = 0;
  kmem.npage = 0;
  freerange(kernel_end, (void*)PHYSTOP);
  #ifdef DEBUG
  printf("kernel_end: %p, phystop: %p\n", kernel_end, (void*)PHYSTOP);
  printf("kinit\n");
  #endif
}

void
freerange(void *pa_start, void *pa_end)
{
  char *p;
  p = (char*)PGROUNDUP((uint64)pa_start);
  for(; p + PGSIZE <= (char*)pa_end; p += PGSIZE)
    kfree(p);
}

// Free the page of physical memory pointed at by v,
// which normally should have been returned by a
// call to kalloc().  (The exception is when
// initializing the allocator; see kinit above.)
void
kfree(void *pa)
{
  struct run *r;

  if(((uint64)pa % PGSIZE) != 0 || (char*)pa < kernel_end || (uint64)pa >= PHYSTOP)
    panic("kfree");

  // Fill with junk to catch dangling refs.
  memset(pa, 1, PGSIZE);

  r = (struct run*)pa;

  acquire(&kmem.lock);
  r->next = kmem.freelist;
  kmem.freelist = r;
  kmem.npage++;
  release(&kmem.lock);
}

// Allocate one 4096-byte page of physical memory.
// Returns a pointer that the kernel can use.
// Returns 0 if the memory cannot be allocated.
void *
kalloc(void)
{
  struct run *r;

  acquire(&kmem.lock);
  r = kmem.freelist;
  if(r) {
    kmem.freelist = r->next;
    kmem.npage--;
  }
  release(&kmem.lock);

  if(r)
    memset((char*)r, 5, PGSIZE); // fill with junk
  return (void*)r;
}

uint64
freemem_amount(void)
{
  return kmem.npage << PGSHIFT;
}

