int ext4_init()
{
#ifdef DEBUG
    printf("[ext4_init] enter!\n");
#endif
    int result;

    const char *mount_point = "/";

    struct ext4_blockdev *blockdev = ext4_blockdev_get();
    result = ext4_device_register(blockdev, "ext4_blockdev");
    if (result != EOK)
    {
        printf("[ext4] device register error! result=%d\n", result);
        return -1;
    }

    result = ext4_mount("ext4_blockdev", mount_point, false);
    if (result != EOK)
    {
        printf("[ext4] mount error! result=%d\n", result);
        return -1;
    }

    result = ext4_recover(mount_point);
    if (result != EOK && result != ENOTSUP)
    {
        printf("[ext4] recover error! result=%d\n", result);
        return -1;
    }

    result = ext4_cache_write_back(mount_point, true);
    if (result != EOK)
    {
        printf("[ext4] cache write back error! result=%d\n", result);
        return -1;
    }

    return 0;
}


