int sigaction(int signum, struct sigaction *act, struct sigaction *oldact)
{
    // printf("sigaction start\n");

    struct proc *current = myproc();

    if (signum < 1 || signum > NSIG)
        return -1;

    if(oldact)
        *oldact = current->sigaction[signum];

    if(act)
        current->sigaction[signum] = *act;

    // printf("sigaction ok\n");

    return 0;
}

int sigprocmask(int how, __sigset_t *set, __sigset_t *oldset)
{
    // printf("sigprocmask start\n");

    struct proc *current = myproc();

    // set->__val[0] &= ~((1 << SIGTERM) | (1 << SIGKILL));
    for (int i = 0; i < SIGSET_LEN; i++){
        if(oldset){
            oldset->__val[i] = current->sig_set.__val[i];
        }

        switch (how)
        {
        case SIG_BLOCK:
            current->sig_set.__val[i] |= set->__val[i];
            break;
        case SIG_UNBLOCK:
            current->sig_set.__val[i] &= ~(set->__val[i]);
            break;
        case SIG_SETMASK:
            current->sig_set.__val[i] = set->__val[i];

