/*

  修改数据段的大小；

  输入：指定待修改的地址；

  返回值：成功返回0，失败返回-1;
*/
uint64
sys_brk(void)
{
  int addr;
  int new_addr;

  if (argint(0, &new_addr) < 0)
    return -1;
  addr = myproc()->sz;
  if (new_addr == 0)
  {
    return addr;
  }
  if (growproc(new_addr - addr) < 0)
    return -1;
  return new_addr;
}

/*

  将文件或设备映射到内存中；

  输入：

  + start: 映射起始位置，

  + len: 长度，

  + prot: 映射的内存保护方式，可取：PROT_EXEC, PROT_READ, PROT_WRITE, PROT_NONE

  + flags: 映射是否与其他进程共享的标志，

  + fd: 文件句柄，

  + off: 文件偏移量；

  返回值：成功返回已映射区域的指针，失败返回-1;
*/
uint64
sys_mmap()
{
  uint64 start_addr;
  int prot,flags,fd,off,len;
  if (argaddr(0,&start_addr) < 0 || argint(1,&len) < 0 || argint(2,&prot) < 0)
    return -1;

  if (argint(3,&flags) < 0 || (argint(4,&fd) < 0) || argint(5,&off) < 0)
    return -1;

  if(fd < 0 || fd >= NOFILE)
    return -1;
  return mmap(start_addr, len, prot, flags, fd, off);
}

/*

