  输入：映射的指定地址及区间；

  返回值：成功返回0，失败返回-1;
*/
uint64
sys_munmap()
{
  uint64 start,len;
  if (argaddr(0,&start) < 0 || argaddr(1,&len) < 0) {
    return -1;
  }
  // return unmmap(start,len);
  return 0;
}

