int filewritev(struct file *f, struct iovec iov[], int iovcnt)
{
  int ret = 0;
  struct ext4_file *file;

  if (!f->writable)
    return -1;

  switch (f->type)
  {
  case FD_PIPE:
    ret = pipewritev(f->pipe, iov, iovcnt);
    break;
  case FD_DEVICE:
    file = &f->file;
    ret = devsw[f->major].writev(1, iov, iovcnt);
    break;
  case FD_ENTRY:
    file = &f->file;
    ret = fwritev(file, iov, iovcnt, f->off);
    if (ret > 0)
    {
      f->off += ret;
    }
    break;
  default:
    panic("filewritev");
  }
  return ret;
}

int filereadv(struct file *f, struct iovec iov[], int iovcnt)
{
  int ret = 0;
  struct ext4_file *file;

  if (!f->readable)
    return -1;

  switch (f->type)
  {
  case FD_PIPE:
    ret = pipereadv(f->pipe, iov, iovcnt);
    break;
  case FD_DEVICE:
    file = &f->file;
    ret = devsw[f->major].readv(1, iov, iovcnt);
    break;
  case FD_ENTRY:
    file = &f->file;
    ret = freadv(file, iov, iovcnt, f->off);
    if (ret > 0)
    {
      f->off += ret;
    }
    break;
  default:
    panic("filereadv");
  }
  return ret;
}

