**关键功能实现**:

1. **进程创建 (fork)**:
```c
int fork(void) {
  struct proc *np;
  struct proc *p = myproc();

  // 分配新进程结构
  if((np = allocproc()) == 0)
    return -1;

  // 复制用户内存
  uvmcopy(p->pagetable, np->pagetable, p->sz);
  np->sz = p->sz;

  // 复制陷阱帧
  *(np->trapframe) = *(p->trapframe);
  np->trapframe->a0 = 0;  // 子进程返回0

  // 复制打开文件
  for(int i = 0; i < NOFILE; i++)
    if(p->ofile[i])
      np->ofile[i] = filedup(p->ofile[i]);

  np->parent = p;
  safestrcpy(np->name, p->name, sizeof(p->name));

  // 设置初始状态
  np->state = RUNNABLE;
  np->context.ra = (uint64)forkret;
  np->context.sp = np->kstack + PGSIZE;

  return np->pid;
}
```

2. **进程调度 (scheduler)**:
```c
void scheduler(void) {
  struct cpu *c = mycpu();
  c->proc = 0;

  for(;;) {
    // 遍历进程表寻找可运行进程
    for(struct proc *p = proc; p < &proc[NPROC]; p++) {
      acquire(&p->lock);
      if(p->state == RUNNABLE) {
        // 切换到进程
        p->state = RUNNING;
        c->proc = p;
        swtch(&c->context, &p->context);
        c->proc = 0;
      }
      release(&p->lock);
    }
  }
}
```

3. **上下文切换 (swtch.S)**:
```assembly
.globl swtch
swtch:
    # 保存callee-saved寄存器到old context
    sd ra, 0(a0)
    sd sp, 8(a0)
    sd s0, 16(a0)
    # ... 保存s1-s11

    # 从new context恢复寄存器
    ld ra, 0(a1)
    ld sp, 8(a1)
    ld s0, 16(a1)
    # ... 恢复s1-s11

    ret
```

4. **clone系统调用**:
支持Linux风格的clone，定义了完整的clone标志：
```c
