#define TRAPFRAME       (TRAMPOLINE - PGSIZE) // 陷阱帧
#define VKSTACK         0x3EC0000000L   // 内核栈虚拟地址
#define MAXUVA          RUSTSBI_BASE    // 用户空间上限
