**文件操作实现**:

```c
int fileread(struct file *f, uint64 addr, int n) {
  int result = 0, rcnt = 0;

  if(f->readable == 0)
    return -1;

  switch (f->type) {
    case FD_PIPE:
      rcnt = piperead(f->pipe, addr, n);
      break;
    case FD_DEVICE:
      if(f->major < 0 || f->major >= NDEV || !devsw[f->major].read)
        return -1;
      rcnt = devsw[f->major].read(1, addr, n);
      break;
    case FD_ENTRY:
      result = fread(&f->file, addr, f->off, n, &rcnt);
      if (result == EOK)
        f->off += rcnt;
      break;
    default:
      panic("fileread");
  }

  return rcnt;
}
```

