1. **用户态陷阱入口 (trampoline.S)**:
```assembly
uservec:
  # 交换a0和sscratch
  csrrw a0, sscratch, a0

  # 保存所有用户寄存器到trapframe
  sd ra, 40(a0)
  sd sp, 48(a0)
  # ... 保存所有通用寄存器

  # 恢复内核栈指针
  ld sp, 8(a0)

  # 恢复内核页表
