2. **陷阱处理函数 (trap.c)**:
```c
void usertrap(void) {
  int which_dev = 0;

  if ((r_sstatus() & SSTATUS_SPP) != 0)
    panic("usertrap: not from user mode");

  w_stvec((uint64)kernelvec);  // 设置内核陷阱向量

  struct proc *p = myproc();
  p->trapframe->epc = r_sepc();  // 保存用户PC

  if (r_scause() == 8) {
    // 系统调用
    if (p->killed == SIGTERM)
      exit(0);

    p->trapframe->epc += 4;  // 跳过ecall指令
    intr_on();
    syscall();
  }
  else if ((which_dev = devintr()) != 0) {
    // 设备中断
  }
  else if (r_scause() == 13 || r_scause() == 15) {
    // 页错误（Load/Store page fault）
    uint64 va = r_stval();

    if (va < PGROUNDUP(p->sz)) {
      // COW未实现
      printf("[pagefault_handler] cow not implemented!\n");
      p->killed = SIGTERM;
    }
    else if (va < MAXUVA) {
      // 惰性分配
      uint sz1;
      if ((sz1 = uvmalloc(p->pagetable, p->kpagetable, p->sz, 
                          PGROUNDUP(va) + PGSIZE)) == 0) {
        p->killed = SIGTERM;
      }
      p->sz = sz1;
      sfence_vma();
    }
  }
  else {
    // 未知异常
    p->killed = SIGTERM;
  }

  // 处理信号
  if (p->killed) {
    if (p->killed == SIGTERM || p->killed == 33)
      exit(0);
    sighandle();
  }

  // 时钟中断触发调度
  if (which_dev == 2)
    yield();

  usertrapret();
}
```

