**信号数据结构**:

```c
#define NSIG 64  // 支持64个信号

struct sigaction {
  union {
    __sighandler_t sa_handler;
  } __sigaction_handler;
  __sigset_t sa_mask;
  int sa_flags;
};

struct sig_frame {
  __sigset_t mask;              // 保存的信号掩码
  struct trapframe *tf;         // 保存的陷阱帧
  struct sig_frame *next;       // 链表指针
};
