}

int consoleread(int user_dst, uint64 dst, int n) {
  uint target;
  int c;
  char cbuf;

  target = n;
  acquire(&cons.lock);
  while(n > 0) {
    // 等待输入
    while(cons.r == cons.w) {
      if(myproc()->killed) {
        release(&cons.lock);
        return -1;
      }
      sleep(&cons.r, &cons.lock);
    }

    c = cons.buf[cons.r++ % INPUT_BUF];

    if(c == C('D')) {  // EOF
      if(n < target) {
        cons.r--;
      }
      break;
    }

    cbuf = c;
    if(either_copyout(user_dst, dst, &cbuf, 1) == -1)
      break;

    dst++;
    --n;

    if(c == '\n')
      break;
  }
  release(&cons.lock);

  return target - n;
}
