### 3.11 进程间通信子系统

**核心文件**:
- `kernel/pipe.c` - 管道实现

**管道数据结构**:

```c
struct pipe {
  struct spinlock lock;
  char data[PIPESIZE];  // 环形缓冲区（512字节）
  uint nread;           // 读指针
  uint nwrite;          // 写指针
  int readopen;         // 读端是否打开
  int writeopen;        // 写端是否打开
};
```

**管道实现**:

```c
int pipealloc(struct file **f0, struct file **f1) {
  struct pipe *pi;

  pi = 0;
  *f0 = *f1 = 0;
  if((*f0 = filealloc()) == NULL || (*f1 = filealloc()) == NULL)
    goto bad;
  if((pi = (struct pipe*)kalloc()) == NULL)
    goto bad;

  pi->readopen = 1;
  pi->writeopen = 1;
  pi->nwrite = 0;
  pi->nread = 0;
  initlock(&pi->lock, "pipe");

  (*f0)->type = FD_PIPE;
  (*f0)->readable = 1;
  (*f0)->writable = 0;
  (*f0)->pipe = pi;

  (*f1)->type = FD_PIPE;
  (*f1)->readable = 0;
  (*f1)->writable = 1;
  (*f1)->pipe = pi;

  return 0;

bad:
  if(pi)
    kfree((char*)pi);
  if(*f0)
    fileclose(*f0);
  if(*f1)
    fileclose(*f1);
  return -1;
}

int pipewrite(struct pipe *pi, uint64 addr, int n) {
  int i;
  char ch;
  struct proc *pr = myproc();

  acquire(&pi->lock);
  for(i = 0; i < n; i++) {
    while(pi->nwrite == pi->nread + PIPESIZE) {  // 缓冲区满
      if(pi->readopen == 0 || pr->killed) {
        release(&pi->lock);
        return -1;
      }
      wakeup(&pi->nread);
      sleep(&pi->nwrite, &pi->lock);
    }
    if(copyin2(&ch, addr + i, 1) == -1)
      break;
    pi->data[pi->nwrite++ % PIPESIZE] = ch;
  }
  wakeup(&pi->nread);
  release(&pi->lock);
  return i;
}

int piperead(struct pipe *pi, uint64 addr, int n) {
  int i;
  struct proc *pr = myproc();
  char ch;

  acquire(&pi->lock);
  while(pi->nread == pi->nwrite && pi->writeopen) {  // 缓冲区空
    if(pr->killed) {
      release(&pi->lock);
      return -1;
    }
    sleep(&pi->nread, &pi->lock);
  }
  for(i = 0; i < n; i++) {
    if(pi->nread == pi->nwrite)
      break;
    ch = pi->data[pi->nread++ % PIPESIZE];
    if(copyout2(addr + i, &ch, 1) == -1)
      break;
  }
  wakeup(&pi->nwrite);
  release(&pi->lock);
  return i;
}
```

**完整性评估**: 90%
- 实现了完整的管道机制
- 支持阻塞I/O
- 支持readv/writev
- 正确处理管道关闭
- **缺少**: 命名管道（FIFO）
- **缺少**: 非阻塞I/O支持
- **缺少**: poll/select支持

## 4. 子系统交互分析

### 4.1 系统调用流程

```
用户程序
  ↓ ecall
trampoline.S (uservec)
  ↓ 保存寄存器，切换页表
trap.c (usertrap)
  ↓ 识别系统调用
syscall.c (syscall)
  ↓ 查表调用
sys*.c (sys_xxx)
  ↓ 调用内核函数
各子系统
  ↓ 返回结果
trap.c (usertrapret)
  ↓ 恢复寄存器，切换页表
trampoline.S (userret)
  ↓ sret
用户程序
```

### 4.2 中断处理流程

```
硬件中断
  ↓
PLIC (plic_claim)
  ↓ 识别中断源
trap.c (devintr)
  ↓ 分发到具体驱动
  ├─ UART中断 → console.c (consoleintr)
  ├─ 磁盘中断 → virtio_disk.c (virtio_disk_intr)
  └─ 时钟中断 → timer.c (timer_tick)
  ↓
PLIC (plic_complete)
```

### 4.3 文件I/O流程

```
用户程序调用read()
  ↓
sysfile.c (sys_read)
  ↓
file.c (fileread)
  ↓ 根据文件类型分发
  ├─ FD_PIPE → pipe.c (piperead)
  ├─ FD_DEVICE → console.c (consoleread)
  └─ FD_ENTRY → fs.c (fread)
       ↓
     lwext4 (ext4_fread)
       ↓
     bio.c (bread)
       ↓
     disk.c (disk_read)
       ↓
     virtio_disk.c (virtio_disk_rw)
       ↓
     硬件
```

